UPDATE resignation_application
resignation_type = #{resignationType}, resignation_reason = #{resignationReason}, resignation_date = #{resignationDate}, handover_info = #{handoverInfo}, handover_to = #{handoverTo}, status = #{status},
WHERE id = #{id}

mapper.select:
SELECT ra.*, e.name AS employee_name, e.dept_id, d.dept_name, ht.name AS handover_to_name, su.username AS submitter_name FROM resignation_application ra JOIN employee e ON ra.employee_id = e.id LEFT JOIN department d ON e.dept_id = d.id LEFT JOIN employee ht ON ra.handover_to = ht.id LEFT JOIN sys_user su ON ra.submitter_id = su.id
AND ra.status = #{status}
AND e.name LIKE CONCAT('%', #{keyword}, '%')
ORDER BY ra.create_time DESC LIMIT #{offset}, #{size}

SELECT COUNT(*) FROM resignation_application ra JOIN employee e ON ra.employee_id = e.id
AND ra.status = #{status}
AND e.name LIKE CONCAT('%', #{keyword}, '%')
